import { Box, Container, Grid, TextField, Typography } from '@material-ui/core';
import { AddRounded } from '@material-ui/icons';
import React from 'react';

const CreateQuiz = () => {
  return (
    <Container>
      <Grid container spacing={2}>
        <Grid item xs={12}>
          <Typography variant='h3'>
            Create Question
          </Typography>
        </Grid>
        <form>
          <Grid item xs={12}>
              <TextField placeholder='Title' variant='outlined' fullWidth />
          </Grid>
          <Grid item xs={12}>
            <Box mb={2}>
              <TextField placeholder='Question' variant='outlined' fullWidth />
            </Box>
            <Box mb={2}>
              <TextField placeholder='Title' variant='outlined' fullWidth />
            </Box>
          </Grid>
        </form>
      </Grid>
    </Container >
  );
}

export default CreateQuiz;
